import{_ as i,p as l,q as e,a1 as a}from"./framework-822ca1a4.js";const n={},o=a('<h1 id="介词" tabindex="-1"><a class="header-anchor" href="#介词" aria-hidden="true">#</a> 介词</h1><p>介词、介系词是语法中定义的一种词汇，用来描述字词之间的时间、空间或文法关系。</p><p>介词不能单独使用，它不能单独做任何句子成分！介词必须跟名词，代词或者其他词语构成介词短语，然后才能造句。</p><h2 id="介词构成方式" tabindex="-1"><a class="header-anchor" href="#介词构成方式" aria-hidden="true">#</a> 介词构成方式</h2><p>介词是一种前置词，必须放在其他词语的前面。这写其他词语叫做介词宾语。介词和介词短语一起就构成了介词短语！根据介词宾语的种类，介词短语有以下几个格式：</p><ol><li>介词 + 名词</li></ol><ul><li>In Xi&#39;an 在西安</li><li>In my room 在我的房间里面</li></ul><ol start="2"><li>介词 + 数词</li></ol><ul><li>In 1998 在 1998 年</li><li>At 5：20 在五点二十分</li></ul><ol start="3"><li>介词 + 代词宾格</li></ol><ul><li>Beside him 在他旁边</li><li>Behind me 在我后面</li></ul><ol start="4"><li>介词 + 动名词短语</li></ol><ul><li>Before sleeping 睡觉之前</li><li>About learning English 关于学英语</li></ul><h2 id="介词短语的作用" tabindex="-1"><a class="header-anchor" href="#介词短语的作用" aria-hidden="true">#</a> 介词短语的作用</h2><p>介词短语的五个作用，分别是：做状语，做后置定语，做表语，做宾补和做主补。</p><ol><li>做状语，可以做时间状语，地点状语，方式状语等。</li></ol><ul><li>I get up at 5:20.</li><li>I was thin in 1998.</li><li>I teach English in Guangxi.</li><li>She went to America by plane.</li></ul><ol start="2"><li>作后置定语</li></ol><ul><li>The book on the table is mine.</li><li>The girl under the tree is beautiful.</li><li>The people from HongKong don&#39;t speak Mandarin.</li></ul><ol start="3"><li>作表语</li></ol><ul><li>I am in Xi&#39;an.</li><li>She is under the tree.</li><li>They are from HongKong.</li></ul><ol start="4"><li>做补语</li></ol><ul><li>I put my book on the table.</li><li>My book is put on the table.</li></ul><h2 id="动词短语和固定搭配" tabindex="-1"><a class="header-anchor" href="#动词短语和固定搭配" aria-hidden="true">#</a> 动词短语和固定搭配</h2><p>介词是前置词，必须放在其他词语前面，构成介词短语。然而，有时候介词会出现在实义动词后面，这个时候，其实已经不属于介词了，而是动词短语，也叫复合动词。例如：</p><ul><li>look for</li><li>look after</li></ul><p>介词短语和动词短语的区别：</p><p>介词短语，可以根据介词的用法自由组合； 动词短语，固定搭配，不能自由组合，只能积累。</p><p>有时候，介词可以跟形容词搭配，并且形容词放 be 动词后面，一起构成一个含有介词的固定搭配，例如：</p><ul><li>be afraid of</li><li>be good at</li><li>be keen on</li></ul><h2 id="介词分讲" tabindex="-1"><a class="header-anchor" href="#介词分讲" aria-hidden="true">#</a> 介词分讲</h2><p>已经对于常见的一些介词详细讲解每一个的用法。</p><h2 id="in" tabindex="-1"><a class="header-anchor" href="#in" aria-hidden="true">#</a> in</h2><ol><li>in + 大地方，意思是“在...”。</li></ol><ul><li><p>in Xi&#39;an</p></li><li><p>in Guangxi</p></li><li><p>in China</p></li><li><p>in America</p></li><li><p>in Asia</p></li><li><p>in the world</p></li><li><p>We live in Chian.</p></li><li><p>I am happy in Xi&#39;an.</p></li><li><p>The people in Asia are poor.</p></li><li><p>We are in Shaanxi.</p></li></ul><ol start="2"><li>in + 表示位置或场所的名词(小地方)，意思是“在...里面”。需要注意，这些位置场所大多数强调内部空间的。</li></ol><ul><li>In the factory</li></ul>',37),t=[o];function r(h,p){return l(),e("div",null,t)}const d=i(n,[["render",r],["__file","preposition.html.vue"]]);export{d as default};
